'use strict';

// Security headers used for both Express and Koa
const SECURITY_HEADERS = {
  'Strict-Transport-Security': 'max-age=63072000; includeSubDomains; preload',
  'X-Frame-Options': 'DENY',
  'X-Content-Type-Options': 'nosniff',
  'Referrer-Policy': 'no-referrer',
  'Permissions-Policy': 'geolocation=(), microphone=()',
  // X-XSS-Protection is deprecated, setting to 0 to opt-out of browser filter
  'X-XSS-Protection': '0',
  // Minimal CSP as an example
  'Content-Security-Policy': "default-src 'self'"
};

function applyHeadersToSetter(setter) {
  for (const [k, v] of Object.entries(SECURITY_HEADERS)) {
    setter(k, v);
  }
}

// Express middleware that sets security headers
function expressMiddleware(req, res, next) {
  applyHeadersToSetter((k, v) => res.set(k, v));
  next();
}

// Express Router exposing GET /status/fo -> { status: 'ok', fortress: true }
let expressRouter;
try {
  // Require express only when building the router so that requiring this file
  // doesn't necessarily crash in environments without express unless the router is used.
  const express = require('express');
  expressRouter = express.Router();
  // Apply headers for all requests handled by this router
  expressRouter.use(expressMiddleware);
  expressRouter.get('/status/fo', (req, res) => {
    res.json({ status: 'ok', fortress: true });
  });
} catch (e) {
  // If express is not available, provide a helpful stub that throws when used.
  expressRouter = {
    use: () => {
      throw new Error('Express is not available: cannot use expressRouter');
    }
  };
}

// Koa-compatible middleware (async) that sets headers and responds to GET /status/fo
async function koaMiddleware(ctx, next) {
  applyHeadersToSetter((k, v) => ctx.set(k, v));

  if (ctx.method === 'GET' && ctx.path === '/status/fo') {
    ctx.status = 200;
    ctx.body = { status: 'ok', fortress: true };
    return;
  }

  await next();
}

module.exports = {
  expressMiddleware,
  expressRouter,
  koaMiddleware
};

